import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { ProductService } from '../../core/services/product.service';
import { CartService } from '../../core/services/cart.service';
import { MoneyPipe } from '../../core/pipes/money.pipe';
import { Product } from '../../core/models';

@Component({
  selector: 'app-catalog',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './catalog.component.html',
  styleUrl: './catalog.component.css',
})
export class CatalogComponent {
  readonly query = signal('');
  readonly justAdded = signal<string | null>(null);

  readonly filtered = computed<Product[]>(() => {
    const q = this.query().trim().toLowerCase();
    return this.productService.products().filter(
      (p) => !q || p.name.toLowerCase().includes(q) || p.description.toLowerCase().includes(q),
    );
  });

  constructor(
    private productService: ProductService,
    private cart: CartService,
    private route: ActivatedRoute,
    private router: Router,
  ) {
    const q = this.route.snapshot.queryParamMap.get('q');
    if (q) this.query.set(q);
  }

  onSearch(value: string): void {
    this.query.set(value);
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { q: value || null },
      queryParamsHandling: 'merge',
    });
  }

  addToCart(product: Product, event: Event): void {
    event.stopPropagation();
    event.preventDefault();
    if (product.stockQty <= 0) return;
    this.cart.addItem(product);
    this.justAdded.set(product.id);
  }
}
